INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 2834, 1, "青空の下で謁見", 5118061, 91002, "フリーマーケット会場", "ペコリーヌとの出会い", 7, 0, 10118, 40, 2, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 2835, 1, "未来の騎空団\nマスコット？", 5118062, 91002, "フリーマーケット会場", "マホとの出会い", 7, 0, 10118, 40, 2, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 2837, 1, "お嬢さまからの\n緊急依頼", 5118063, 91002, "ランドソル市街地", "アキノとの出会い", 7, 0, 10118, 40, 2, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 4108402, 1, "黄金色の悩みごと", 5118064, 91002, "フリーマーケット会場", "ジュンとの出会い", 18, 0, 10118, 40, 2, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 4107402, 1, "白熱！　格闘大会！", 5118065, 91002, "フリーマーケット会場", "カオリとの出会い", 18, 0, 10118, 40, 2, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 9000227, 1, "祭り太鼓はオーエドの華", 5118066, 91002, "オーエド町", "ニノンとの出会い", 16, 1, 10118, 40, 2, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 2101181, 1, "人気者は遅れて\nやってくる", 5118067, 91002, "フリーマーケット会場", "スズナとの出会い", 19, 0, 10118, 40, 3, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 4109402, 1, "巫女・ミーツ・魔法少女", 5118068, 91002, "ランドソル市街地", "ナナカとの出会い", 18, 0, 10118, 40, 3, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 4305402, 1, "ネズ耳は二度なくなる", 5118069, 91002, "フリーマーケット会場", "キャル＆コッコロとの出会い", 18, 0, 10118, 40, 3, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 4101402, 1, "この出会いにカンパイ！", 5118070, 91002, "ランドソル市街地", "ユカリとの出会い", 18, 0, 10118, 40, 3, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 4106402, 1, "陰陽アンサンブル", 5118071, 91002, "ランドソル市街地", "アオイとの出会い", 18, 0, 10118, 40, 3, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 2836, 1, "運試し十番勝負！", 5118072, 91002, "フリーマーケット会場", "シノブとの出会い", 7, 1, 10118, 40, 3, 8, 20063115);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (0, 0, 0, "彼女たちの新たな日常", 5118600, 0, 0, "オープニング", 0, 0, 10118, 0, 1, 0, 20063115);
